def posMap(pos, tar_len ,cur_len): return round((pos + 1)*(tar_len/cur_len) + 0.5 - 1e-6) - 1 

def getTrace_LV1_to_16(val=1):

    trace = []

    
    for r in range(1):
        for c in range(1):
            trace.append({"lv": 0, 
                "rects": [
                          (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          ], 
                "pos": [0, val, val]})


    for r in range(2):
        for c in range(2):
            trace.append({"lv": 1, 
                "rects": [
                          (0, 1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1), 
                          (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          ], 
                "pos": [0, val, val]})
     

    for r in range(4):
        for c in range(4):
            trace.append({"lv": 2, 
                "rects": [
                          (0, 1, abs(0+r-1)//4, abs(0+r-1)//4 + 2*val+1, abs(0+r-1)//4, abs(0+r-1)//4 + 2*val+1), 
                          (0, 1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1), 
                          (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          ], 
                "pos": [0, val, val]})
     

    for r in range(8):
        for c in range(8):
            trace.append({"lv": 3, 
                "rects": [
                          (0, 1, abs(0+r-1)//8, abs(0+r-1)//8 + 2*val+1, abs(0+r-1)//8, abs(0+r-1)//8 + 2*val+1), 
                          (0, 1, abs(0+r-1)//4, abs(0+r-1)//4 + 2*val+1, abs(0+r-1)//4, abs(0+r-1)//4 + 2*val+1), 
                          (0, 1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1), 
                          (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          ], 
                "pos": [0, val, val]})


    for r in range(16):
        for c in range(16):
            trace.append({"lv": 4, 
                "rects": [
                          (0, 1, abs(0+r-1)//16, abs(0+r-1)//16 + 2*val+1, abs(0+r-1)//16, abs(0+r-1)//16 + 2*val+1), 
                          (0, 1, abs(0+r-1)//8, abs(0+r-1)//8 + 2*val+1, abs(0+r-1)//8, abs(0+r-1)//8 + 2*val+1), 
                          (0, 1, abs(0+r-1)//4, abs(0+r-1)//4 + 2*val+1, abs(0+r-1)//4, abs(0+r-1)//4 + 2*val+1), 
                          (0, 1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1, abs(0+r-1)//2, abs(0+r-1)//2 + 2*val+1), 
                          (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c), 
                          ], 
                "pos": [0, val, val]})

    # left, right, top, bottom, front, back
    # funs means there are multiple padding functions
    padding_funs = []
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))

    padding_val = val

    return trace, padding_funs, padding_val


