def getTrace_LV3_8_16_32_t1(val=3):

    trace = []

    for r in range(8):
        for c in range(8):
            trace.append({"lv": 0, 
                "rects": [
                          (0, 1, 0+r+1, 2*val+1+r-1, 0+c+1, 2*val+1+c-1), 
                          (0, 1, 0+1, 2*val+1-1, 0+1, 2*val+1-1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          ], 
                "pos": [0, val, val]})


    for r in range(16):
        for c in range(16):
            trace.append({"lv": 1, 
                "rects": [
                          (0, 1, abs(0+r-1)//2 + 1, abs(0+r-1)//2 + 2*val+1-1, abs(0+c-1)//2+1, abs(0+c-1)//2 + 2*val+1-1), 
                          (0, 1, 0+r+1, 2*val+1+r-1, 0+c+1, 2*val+1+c-1), 
                          (0, 1, 0, 2*val+1, 0, 2*val+1), 
                          ], 
                "pos": [0, val, val]})


    for r in range(32):
        for c in range(32):
            trace.append({"lv": 2, 
                "rects": [
                          (0, 1, abs(0+r-1)//4+1, abs(0+r-1)//4 + 2*val+1-1, abs(0+c-1)//4+1, abs(0+c-1)//4 + 2*val+1-1), 
                          (0, 1, abs(0+r-1)//2+1, abs(0+r-1)//2 + 2*val+1-1, abs(0+c-1)//2+1, abs(0+c-1)//2 + 2*val+1-1), 
                          (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c), 
                          ], 
                "pos": [0, val, val]})


    # left, right, top, bottom, front, back
    # funs means there are multiple padding functions
    padding_funs = []
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))

    padding_val = val

    return trace, padding_funs, padding_val

