def getTrace_PF_L32X32_F1X1_lv1_CHL1(val=6):

    trace = []
    
    for r in range(32):
        for c in range(32):
            trace.append({"lv": 1, "rects": [(0, 2, 0+r, 2*val+1+r, 0+c, 2*val+1+c), (0, 1, 0+r, 2*val+1+r, 0+c, 2*val+1+c)], "pos": [(0, val, val)], "lv_msk": [0]})
               
#     trace.append({"lv": 1, "rects": [(0, 2, 0, 3+4, 0, 3    +4), (0, 1, 0, 3+4, 0, 3    +4)], "pos": [(0, 1+2, 1+2)], "lv_msk": [0]})
#     trace.append({"lv": 1, "rects": [(0, 2, 0, 3+4, 1, 4    +4), (0, 1, 0, 3+4, 1, 4    +4)], "pos": [(0, 1+2, 1+2)], "lv_msk": [0]})
#     trace.append({"lv": 1, "rects": [(0, 2, 0, 3+4, 2, 5    +4), (0, 1, 0, 3+4, 2, 5    +4)], "pos": [(0, 1+2, 1+2)], "lv_msk": [0]})
                                                                                                               
                                                                                                                              
    # left, right, top, bottom, front, back                                                                                   
    padding = []                                                                                                              
    padding.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))                                                                   
    padding.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))                                                                   
                                                                                                   
#    return trace, padding
    padding_val = val

    return trace, padding, padding_val










