def getTrace_cifar_dynamic(size_list, offp_list, val=10):

    def posMap(pos, tar_len ,cur_len): return round((pos + 1)*(tar_len/cur_len) + 0.5 - 1e-6) - 1 

    import random 
    

   # lv_list     = [0, 1, 2, 3, 4, 5, 6]
    # size_list    = [(1, 1), (2, 2), (4, 4), (8, 8), (16, 16), (32, 32), (32, 32)]
    # offp_list = [10, 9, 9, 7, 8, 8, 8]

    lv_list = range(len(offp_list))


    trace = []



#    lv = lv_list[0]
    for lv in lv_list:

        pos_list = []
        for r in range(size_list[lv][0]): 
            for c in range(size_list[lv][1]): 
                pos_list.append([r, c])

        random.shuffle(pos_list)

        for t in range(len(pos_list)):
            r = pos_list[t][0]; c = pos_list[t][1]

            entry = {}
            entry["lv"] = lv
            entry["pos"] = [0, val -offp_list[lv], val -offp_list[lv]]

            entry["rects"] = []
            for lv_t in range(len(lv_list)):
                if lv_t < lv + 1e-6:
                    entry["rects"].append((0, 1, posMap(r, size_list[lv_t][0], size_list[lv][0]) +          offp_list[lv_t], 
                                                 posMap(r, size_list[lv_t][0], size_list[lv][0]) + 2*val+1 -offp_list[lv_t], 
                                                 posMap(c, size_list[lv_t][1], size_list[lv][1]) +          offp_list[lv_t], 
                                                 posMap(c, size_list[lv_t][1], size_list[lv][1]) + 2*val+1 -offp_list[lv_t]))
            # 由于infer中有mask判断机制，所以后面的(0, 1, 0, 2*val+1, 0, 2*val+1), 可以直接删除
            
            trace.append(entry)




    # left, right, top, bottom, front, back
    # funs means there are multiple padding functions
    padding_funs = []
    for _ in range(len(lv_list)):
        padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    #padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    #padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    #padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    #padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))
    #padding_funs.append(nn.ConstantPad3d((val, val, val, val, 0, 0), 0))

    

    padding_val = val

    return trace, padding_funs, padding_val





